def solve(age, heart_rate, hypertension, myocardial_infarction, stroke, renal_insufficiency, anemia, lvef, ctn_elevation, ecg_change):
    # Step 1: Calculate age score based on the patient's age
    if age < 40:
        age_score = 0
    elif 40 <= age <= 49:
        age_score = 9
    elif 50 <= age <= 59:
        age_score = 29
    elif 60 <= age <= 64:
        age_score = 41
    elif 65 <= age <= 69:
        age_score = 50
    elif 70 <= age <= 74:
        age_score = 58
    elif 75 <= age <= 79:
        age_score = 65
    else:  # age >= 80
        age_score = 71
    yield {
        "step_name": "age_score_calculation",
        "step_description": "Calculate the score based on the patient's age according to the OPT-CAD scoring rules.",
        "step_result": age_score,
        "unit": None
    }

    # Step 2: Calculate heart rate score based on the patient's heart rate
    if heart_rate < 60:
        heart_rate_score = 0
    elif 60 <= heart_rate <= 69:
        heart_rate_score = 14
    elif 70 <= heart_rate <= 79:
        heart_rate_score = 18
    elif 80 <= heart_rate <= 89:
        heart_rate_score = 21
    elif 90 <= heart_rate <= 99:
        heart_rate_score = 24
    elif 100 <= heart_rate <= 110:
        heart_rate_score = 30
    else:  # heart_rate > 110
        heart_rate_score = 36
    yield {
        "step_name": "heart_rate_score_calculation",
        "step_description": "Calculate the score based on the patient's heart rate according to the OPT-CAD scoring rules.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 3: Calculate hypertension score based on the presence of hypertension
    if hypertension:
        hypertension_score = 20
    else:
        hypertension_score = 0
    yield {
        "step_name": "hypertension_score_calculation",
        "step_description": "Calculate the score based on the presence of hypertension according to the OPT-CAD scoring rules.",
        "step_result": hypertension_score,
        "unit": None
    }

    # Step 4: Calculate myocardial infarction score based on the presence of a history of myocardial infarction
    if myocardial_infarction:
        myocardial_infarction_score = 16
    else:
        myocardial_infarction_score = 0
    yield {
        "step_name": "myocardial_infarction_score_calculation",
        "step_description": "Calculate the score based on the presence of a history of myocardial infarction according to the OPT-CAD scoring rules.",
        "step_result": myocardial_infarction_score,
        "unit": None
    }

    # Step 5: Calculate stroke score based on the presence of a history of stroke
    if stroke:
        stroke_score = 16
    else:
        stroke_score = 0
    yield {
        "step_name": "stroke_score_calculation",
        "step_description": "Calculate the score based on the presence of a history of stroke according to the OPT-CAD scoring rules.",
        "step_result": stroke_score,
        "unit": None
    }

    # Step 6: Calculate renal insufficiency score based on the presence of renal insufficiency
    if renal_insufficiency:
        renal_insufficiency_score = 21
    else:
        renal_insufficiency_score = 0
    yield {
        "step_name": "renal_insufficiency_score_calculation",
        "step_description": "Calculate the score based on the presence of renal insufficiency (eGFR < 60 ml/(min·1.73m²)) according to the OPT-CAD scoring rules.",
        "step_result": renal_insufficiency_score,
        "unit": None
    }

    # Step 7: Calculate anemia score based on the presence of anemia
    if anemia:
        anemia_score = 19
    else:
        anemia_score = 0
    yield {
        "step_name": "anemia_score_calculation",
        "step_description": "Calculate the score based on the presence of anemia according to the OPT-CAD scoring rules.",
        "step_result": anemia_score,
        "unit": None
    }

    # Step 8: Calculate LVEF score based on the presence of LVEF < 50%
    if lvef:
        lvef_score = 22
    else:
        lvef_score = 0
    yield {
        "step_name": "lvef_score_calculation",
        "step_description": "Calculate the score based on the presence of LVEF < 50% according to the OPT-CAD scoring rules.",
        "step_result": lvef_score,
        "unit": None
    }

    # Step 9: Calculate cTn elevation score based on the presence of cTn elevation
    if ctn_elevation:
        ctn_elevation_score = 23
    else:
        ctn_elevation_score = 0
    yield {
        "step_name": "ctn_elevation_score_calculation",
        "step_description": "Calculate the score based on the presence of cTn elevation according to the OPT-CAD scoring rules.",
        "step_result": ctn_elevation_score,
        "unit": None
    }

    # Step 10: Calculate ECG change score based on the presence of ECG changes
    if ecg_change:
        ecg_change_score = 13
    else:
        ecg_change_score = 0
    yield {
        "step_name": "ecg_change_score_calculation",
        "step_description": "Calculate the score based on the presence of ECG changes according to the OPT-CAD scoring rules.",
        "step_result": ecg_change_score,
        "unit": None
    }

    # Step 11: Calculate total OPT-CAD score by summing all individual component scores
    total_opt_cad_score = (
        age_score + heart_rate_score + hypertension_score +
        myocardial_infarction_score + stroke_score + renal_insufficiency_score +
        anemia_score + lvef_score + ctn_elevation_score + ecg_change_score
    )
    yield {
        "step_name": "total_opt_cad_score_calculation",
        "step_description": "Calculate the total OPT-CAD score by summing all individual component scores.",
        "step_result": total_opt_cad_score,
        "unit": None
    }

    return total_opt_cad_score
